stage1.reasoning_structure:
{
  "plan_name": "Five-Object Ordering CSP Solver",
  "version": "1.0",
  "goal": "Given logical constraints about the ordering of five objects, deduce the correct ordering or answer a targeted question.",
  "scope": "Exactly five distinct items in a single left-to-right order with positions 1–5.",
  "conventions": {
    "positions": [1, 2, 3, 4, 5],
    "axis": "left-to-right; smaller index = further left/earlier",
    "terms": {
      "before": "pos(A) < pos(B)",
      "after": "pos(A) > pos(B)",
      "adjacent": "|pos(A) - pos(B)| = 1",
      "immediately_before": "pos(B) = pos(A) + 1",
      "immediately_after": "pos(A) = pos(B) + 1",
      "exactly_k_between": "|pos(A) - pos(B)| = k + 1",
      "not_adjacent": "|pos(A) - pos(B)| >= 2",
      "between(Y,Z)": "X is strictly between Y and Z: min(pos(Y), pos(Z)) < pos(X) < max(pos(Y), pos(Z))"
    },
    "closed_world": "If not stated, it is unconstrained.",
    "ambiguity_policy": "If multiple solutions fit, report non-uniqueness or what is invariant."
  },
  "assumptions": [
    "Five distinct items map one-to-one to positions 1–5.",
    "All clues refer to the single left-to-right axis.",
    "Between means strictly between and order-agnostic.",
    "Immediately before/after means adjacent in that order.",
    "If puzzle wording is unclear, adopt these conventions and state them in the answer."
  ],
  "inputs": {
    "items": ["A", "B", "C", "D", "E"],
    "rename_map": {
      "note": "Optional mapping from original names to short labels A–E",
      "example": {
        "Alice": "A",
        "Bob": "B",
        "Cara": "C",
        "Don": "D",
        "Eli": "E"
      }
    },
    "query": {
      "type": "one_of[full_order, position_of, relation]",
      "target": "if position_of: item label; if relation: {x, y} pair; else null"
    },
    "clues_raw": [
      "Verbal clues as given by the puzzle"
    ]
  },
  "constraint_schema": {
    "normalized_types": [
      { "type": "fixed", "fields": ["item", "pos"], "meaning": "pos(item) = pos" },
      { "type": "notPos", "fields": ["item", "pos"], "meaning": "pos(item) != pos" },
      { "type": "before", "fields": ["a", "b"], "meaning": "pos(a) < pos(b)" },
      { "type": "adjacent", "fields": ["a", "b"], "meaning": "|pos(a)-pos(b)| = 1 (unordered adjacency)" },
      { "type": "immediatelyBefore", "fields": ["a", "b"], "meaning": "pos(b) = pos(a) + 1" },
      { "type": "distanceEq", "fields": ["a", "b", "d"], "meaning": "|pos(a)-pos(b)| = d (d>=1)" },
      { "type": "distanceGe", "fields": ["a", "b", "dmin"], "meaning": "|pos(a)-pos(b)| >= dmin" },
      { "type": "between", "fields": ["x", "y", "z"], "meaning": "min(pos(y), pos(z)) < pos(x) < max(pos(y), pos(z))" }
    ],
    "normalization_rules": [
      "Translate 'after A' to before(A, X) or before(X, A) consistently: always use 'before'.",
      "Translate 'immediately after A' as immediatelyBefore(A, X) with swapped args where needed.",
      "Translate 'exactly k between A and B' to distanceEq(A, B, k+1).",
      "Translate 'not adjacent' to distanceGe(A, B, 2).",
      "Expand endpoint bans as notPos(item, 1) and/or notPos(item, 5) when implied (e.g., between).",
      "Remove duplicates; keep a single canonical list."
    ]
  },
  "state": {
    "domains": {
      "A": [1, 2, 3, 4, 5],
      "B": [1, 2, 3, 4, 5],
      "C": [1, 2, 3, 4, 5],
      "D": [1, 2, 3, 4, 5],
      "E": [1, 2, 3, 4, 5]
    },
    "rev_domains": {
      "1": ["A", "B", "C", "D", "E"],
      "2": ["A", "B", "C", "D", "E"],
      "3": ["A", "B", "C", "D", "E"],
      "4": ["A", "B", "C", "D", "E"],
      "5": ["A", "B", "C", "D", "E"]
    },
    "assignments": {},
    "constraints": [],
    "precedence_dag": {
      "edges": [],
      "closure": []
    },
    "logs": []
  },
  "steps": [
    {
      "id": "S1",
      "name": "Normalize names, positions, and clues",
      "actions": [
        "Map original item names to A–E; record rename_map.",
        "Set positions = [1,2,3,4,5].",
        "Parse each clue and translate to normalized constraints per constraint_schema.normalized_types.",
        "Derive immediate endpoint bans: e.g., between(X,Y,Z) => notPos(X,1), notPos(X,5).",
        "Consolidate constraints; remove duplicates.",
        "Record all normalized constraints in state.constraints.",
        "If any assumption is unclear in the prompt, add a note to logs describing the adopted convention."
      ],
      "outputs": ["updated state.constraints", "logs"]
    },
    {
      "id": "S2",
      "name": "Initialize candidate sets",
      "actions": [
        "Initialize domains for each item to {1..5}.",
        "Initialize rev_domains for each position to all items.",
        "Apply fixed constraints: for each fixed(item,pos), set assignments[item]=pos and prune domains/rev_domains accordingly."
      ],
      "outputs": ["state.domains", "state.rev_domains", "state.assignments"]
    },
    {
      "id": "S3",
      "name": "Immediate eliminations and endpoint logic",
      "actions": [
        "For each notPos(item,pos), remove pos from domains[item] and item from rev_domains[pos].",
        "For each immediatelyBefore(a,b): remove 5 from domains[a] and 1 from domains[b].",
        "For each distanceEq(a,b,d) with d=4: enforce {a,b} = {pos 1, pos 5}.",
        "For between(x,y,z): remove 1 and 5 from domains[x]; if y or z fixed, tighten x's domain to (min, max) open interval."
      ],
      "outputs": ["pruned domains/rev_domains", "logs"]
    },
    {
      "id": "S4",
      "name": "Build and simplify precedence chains",
      "actions": [
        "Construct precedence_dag.edges from all before(a,b) constraints.",
        "Compute transitive closure; add implied before edges (a<b and b<c -> a<c).",
        "Detect cycles; if found, report contradiction and backtrack/fail.",
        "From closure, derive lower/upper bounds: min_pos(item) >= 1 + count(strict predecessors); max_pos(item) <= 5 - count(strict successors). Prune domains accordingly.",
        "If an entire chain length forces endpoints (e.g., 4-length chain), apply endpoint placement bans/requirements."
      ],
      "outputs": ["precedence_dag", "domain bounds", "logs"]
    },
    {
      "id": "S5",
      "name": "Propagate adjacency and distance",
      "actions": [
        "For adjacent(a,b): prune domains so each remaining pos(p) for a has at least one q in domains[b] with |p-q|=1; symmetrically for b.",
        "For immediatelyBefore(a,b): enforce pos(b) = pos(a)+1 by pruning incompatible positions from both domains.",
        "For distanceEq(a,b,d): prune domains so each remaining pos(p) for a has at least one q for b with |p-q|=d; symmetrically for b.",
        "For distanceGe(a,b,dmin): remove any (p,q) pairs with |p-q| < dmin by pruning p or q if unsupported.",
        "For between(x,y,z): ensure for each candidate p for x there exist q in domains[y] and r in domains[z] such that min(q,r) < p < max(q,r); otherwise remove p."
      ],
      "outputs": ["further pruned domains/rev_domains", "logs"]
    },
    {
      "id": "S6",
      "name": "All-different enforcement and singleton assignments",
      "actions": [
        "If any item domain becomes a singleton {p}, assign item->p; remove item from all other rev_domains and p from all other item domains.",
        "If any position rev_domain becomes a singleton {item}, assign item->position; remove from others.",
        "On each assignment, re-apply S3–S5 incrementally (forward checking).",
        "If any domain becomes empty, report contradiction and backtrack/fail."
      ],
      "outputs": ["updated assignments", "pruned domains/rev_domains", "logs"]
    },
    {
      "id": "S7",
      "name": "Iterate propagation to fixed point",
      "actions": [
        "Repeat S3–S6 until no domain or assignment changes.",
        "Continuously sanity-check that all constraints remain satisfiable (no empty support).",
        "Exploit extremal logic: for tight distances/adjacencies, check endpoints feasibility and prune."
      ],
      "outputs": ["stable state or detection of contradiction", "logs"]
    },
    {
      "id": "S8",
      "name": "Branching (if unresolved)",
      "actions": [
        "If query is already uniquely determined (see S10), skip branching.",
        "Select a branch variable using smallest-domain-first heuristic (tie-break by most constraints).",
        "For each candidate value in that domain, create a branch: tentatively assign and run S3–S7 (forward checking).",
        "If a branch leads to contradiction, discard it.",
        "If multiple branches succeed and the query is a targeted relation that is invariant across branches, answer it; otherwise report non-uniqueness or continue to search for uniqueness if full order is required."
      ],
      "outputs": ["either a unique consistent state, multiple consistent states, or no solution", "logs"]
    },
    {
      "id": "S9",
      "name": "Validation",
      "actions": [
        "Construct a candidate full order from assignments when all 5 positions are filled.",
        "Verify each original clue literally against the constructed order.",
        "If any clue fails, mark contradiction and backtrack/fail.",
        "If not fully assigned but the query is a relation that can be decided from current domains/precedence, proceed to S10."
      ],
      "outputs": ["validated order or confirmation of consistency", "logs"]
    },
    {
      "id": "S10",
      "name": "Answer extraction (core objective)",
      "actions": [
        "If query.type == full_order: return the unique order [pos1..pos5] mapped back to original names.",
        "If query.type == position_of: return the unique position if determined; if multiple, report the set of possible positions.",
        "If query.type == relation: deduce whether pos(x) < pos(y), pos(x) = pos(y) (impossible here), or pos(x) > pos(y) is forced. If not forced, report both possibilities.",
        "If puzzle admits multiple full orders, report non-uniqueness and any invariants (e.g., fixed endpoints or fixed relative orders) if asked."
      ],
      "outputs": ["final answer object", "explanatory notes where needed"]
    }
  ],
  "propagation_rules": [
    "Before(a,b): remove 5 from domains[a], 1 from domains[b]; enforce max(dom[a]) < min(dom[b]) when possible by pruning.",
    "Chain tightening: if a<b and b<c, add a<c; propagate bounds.",
    "ImmediatelyBefore(a,b): model as a block (a,b) of length 2 sliding over positions 1–4; if a fixed, set b accordingly; if b fixed, set a=b-1.",
    "Adjacent(a,b): forbid endpoints that lack an adjacent partner (e.g., if b cannot be at 2, then a cannot be at 1).",
    "DistanceEq and DistanceGe: maintain mutual support; remove unsupported positions.",
    "Between(x,y,z): x cannot be 1 or 5; if y or z fixed, narrow x to strictly between them; if both ranges are narrow, intersect feasible p for x with union over supports."
  ],
  "branching_strategy": {
    "variable_selection": "Item with smallest remaining domain (>1); tie-break by greatest number of incident constraints.",
    "value_ordering": "Try positions in increasing order unless heuristic suggests otherwise (e.g., try endpoints first if heavily constrained).",
    "state_management": "On branch: deep-copy state or use trail of reversible operations; on failure: revert and try next value.",
    "early_exit": "Stop search as soon as the query is uniquely determined."
  },
  "consistency_checks": [
    "No item has an empty domain.",
    "Every constraint has at least one supporting assignment within current domains.",
    "Precedence DAG is acyclic.",
    "All-different: no two items assigned the same position."
  ],
  "output_spec": {
    "full_order": {
      "format": { "positions": ["pos1_item", "pos2_item", "pos3_item", "pos4_item", "pos5_item"] },
      "also_return": { "mapping": "Map back to original names if rename_map provided" }
    },
    "position_of": {
      "format": { "item": "A", "position": 3, "certainty": "unique|one_of", "candidates_if_ambiguous": [2, 3] }
    },
    "relation": {
      "format": { "x": "A", "y": "B", "relation": "x_before_y|x_after_y|undetermined" }
    },
    "ambiguity_reporting": {
      "format": {
        "status": "unique|multiple|none",
        "solutions_count": "if computed",
        "invariants": ["e.g., A before C", "E is last"],
        "notes": "brief explanation"
      }
    }
  },
  "execution_notes": [
    "Prefer deductions that prune multiple domains at once (high leverage).",
    "Record each deduction in logs with cause and effect for traceability.",
    "When stalled, re-check combined effects of constraints (e.g., adjacency with precedence) for hidden prunings.",
    "Verify the final answer against the literal wording of clues before returning."
  ]
}

