        "type": "not_at_ends",
        "schema": { "object": "A" }
      },
      {
        "type": "exclusion_set",
        "schema": { "object": "A", "positions_forbidden": [1, 5] }
      }
    ],
    "disambiguation_notes": [
      "next to = adjacent = |pos(X) − pos(Y)| = 1",
      "before/left of = strictly less than; does not imply adjacency",
      "immediately before = pos(X) = pos(Y) − 1",
      "between is strict: Y < X < Z or Z < X < Y",
      "ends are positions 1 and 5"
    ]
  },
  "prioritization": {
    "module": 9,
    "order": [
      "absolutes and ends (absolute_position, not_at_ends, explicit exclusions)",
      "exact spacing and immediate relations (spacing_exact, immediately_before/after)",
      "adjacency and non-adjacency",
      "general left/right (left_of) and betweenness",
      "transitive closure and propagation",
      "branching on smallest candidate set if needed"
    ],
    "high_leverage_focus": [
      "objects referenced by multiple constraints",
      "positions at extremes (1 and 5)"
    ]
  },
  "inference_rules": {
    "module": 38,
    "rules": [
      {
        "name": "Place Absolute",
        "if": { "type": "absolute_position", "object": "X", "position": "p" },
        "then": [
          "Set placements[p] = X",
          "Remove p from candidates of all other objects",
          "Reduce candidates_per_object[X] to {p}"
        ]
      },
      {
        "name": "Exclude Ends",
        "if": { "type": "not_at_ends", "object": "X" },
        "then": [
          "Remove positions 1 and 5 from candidates_per_object[X]"
        ]
      },
      {
        "name": "Left-of Bounds",
        "if": { "type": "left_of", "left": "A", "right": "B" },
        "then": [
          "For each p in candidates[A], remove p if no q in candidates[B] with q > p",
          "For each q in candidates[B], remove q if no p in candidates[A] with p < q",
          "Derived: A cannot be in position 5; if A must be left of k distinct others, A cannot be in last k positions"
        ]
      },
      {
        "name": "Immediate Before",
        "if": { "type": "immediately_before", "before": "A", "after": "B" },
        "then": [
          "Candidates[A] ⊆ {1,2,3,4}",
          "Candidates[B] ⊆ {2,3,4,5}",
          "Enforce: for any p in candidates[A], p+1 must be in candidates[B]; otherwise remove p",
          "For any q in candidates[B], q−1 must be in candidates[A]; otherwise remove q"
        ]
      },
      {
        "name": "Immediate After",
        "if": { "type": "immediately_after", "after": "A", "before": "B" },
        "then": [
          "Equivalent to: immediately_before(B, A); apply Immediate Before"
        ]
      },
      {
        "name": "Adjacency",
        "if": { "type": "adjacent", "x": "A", "y": "B" },
        "then": [
          "Remove positions 1 from A unless 2 is candidate for B; remove 5 from A unless 4 is candidate for B",
          "Symmetric for B with A",
          "Enforce mutual support: keep only positions p in A where p±1 is candidate for B, and vice versa"
        ]
      },
      {
        "name": "Non-Adjacency",
        "if": { "type": "not_adjacent", "x": "A", "y": "B" },
        "then": [
          "Remove any p from A if p±1 is the only position for B; and vice versa",
          "When one gets placed at position p, immediately remove p±1 from the other's candidates"
        ]
      },
      {
        "name": "Exact Spacing",
        "if": { "type": "spacing_exact", "x": "A", "y": "B", "k": "k" },
        "then": [
          "Allowed pairs are (1,1+k)...(5−k,5) in both orders",
          "Restrict candidates[A] and candidates[B] to positions that can pair with the other at distance k",
          "If one is placed, place or reduce the other to the corresponding position(s)"
        ]
      },
      {
        "name": "Betweenness",
        "if": { "type": "betweenness", "middle": "X", "end1": "Y", "end2": "Z" },
        "then": [
          "Enforce Y < X < Z or Z < X < Y",
          "Remove ends 1 and 5 from X",
          "Prune candidates so that X has at least one position strictly between feasible Y and Z positions"
        ]
      },
      {
        "name": "Transitivity",
        "if": { "facts": ["A < B", "B < C"] },
        "then": [
          "Add A < C",
          "Apply Left-of Bounds pruning for A < C"
        ]
      },
      {
        "name": "Uniqueness per Position",
        "if": { "placements[p]": "X" },
