stage1.reasoning_structure:
{
  "name": "DateReasoningPlan",
  "version": "1.0",
  "purpose": "Step-by-step plan to compute a single specific calendar date from textual clues.",
  "assumptions": {
    "calendar": "Proleptic Gregorian",
    "next_weekday_definition": "First such weekday strictly after the reference date",
    "previous_weekday_definition": "First such weekday strictly before the reference date",
    "relative_days_rule": "\"N days after\" means add N days exclusive of the start date; \"N days before\" means subtract N days exclusive of the start date",
    "holidays_locale_default": "US_federal_if_required_and_unspecified",
    "year_inference": "If not explicit, infer from anchors/holidays/context; if still unclear, treat as ambiguous",
    "output_format": "MM/DD/YYYY zero-padded"
  },
  "data_model": {
    "inputs": {
      "prompt_text": "string"
    },
    "state": {
      "anchors": [
        {
          "type": "explicit_date | weekday | holiday | relative_phrase",
          "value": "string",
          "normalized": "ISO components when applicable",
          "span": "text indices (optional)"
        }
      ],
      "constraints": {
        "day_of_week": "optional string (e.g., Monday)",
        "holiday": "optional string (e.g., Thanksgiving)",
        "nth_weekday": {
          "n": "integer",
          "weekday": "0-6 (Mon=0)",
          "month": "1-12",
          "year": "YYYY or null"
        },
        "relative_offsets": [
          {
            "relation": "after | before | next | previous | on_or_after | on_or_before",
            "quantity": "integer days or weeks",
            "unit": "days | weeks",
            "reference": "anchor id or computed date"
          }
        ],
        "range_limits": {
          "start": "YYYY-MM-DD or null",
          "end": "YYYY-MM-DD or null"
        },
        "explicit_year": "YYYY or null",
        "locale": "string or null"
      },
      "context": {
        "year": "YYYY or null",
        "locale": "string (default US) or null"
      },
      "candidates": [
        {
          "date": "YYYY-MM-DD",
          "sources_used": ["anchor ids and rules"],
          "status": "provisional | validated | discarded",
          "notes": "string"
        }
      ],
      "final_date": "YYYY-MM-DD or null",
      "ambiguity_reasons": ["string"],
      "inconsistency_reasons": ["string"]
    }
  },
  "helpers": {
    "is_leap_year(YYYY)": "return (YYYY % 4 == 0) and (YYYY % 100 != 0 or YYYY % 400 == 0)",
    "month_length(YYYY, MM)": "return 31/30/28/29 depending on month and leap year",
    "day_of_week(YYYY, MM, DD)": "return 0-6 for Mon-Sun",
    "add_days(YYYY, MM, DD, n)": "return date plus n days with rollover",
    "diff_days(dateA, dateB)": "signed integer days B - A",
    "next_weekday(from_date, weekday)": "strictly after from_date",
    "previous_weekday(from_date, weekday)": "strictly before from_date",
    "nth_weekday_of_month(YYYY, MM, weekday, n)": "n>0 from start; n<0 from end (e.g., -1 = last)",
    "compute_holiday_date(name, YYYY, locale)": "return YYYY-MM-DD per locale rules",
    "parse_dates_and_terms(text)": "extract explicit dates (MM/DD/YYYY, Month DD, YYYY, DD Month, etc.), weekdays, holidays, relative phrases and quantities",
    "format_mmddyyyy(YYYY, MM, DD)": "return zero-padded MM/DD/YYYY"
  },
  "plan": [
    {
      "id": 1,
      "name": "Parsing",
      "actions": [
        "Extract all explicit dates (with or without year), weekdays, holidays, relative phrases (e.g., N days after/before, next/previous <weekday>, nth <weekday> of <month>, end of month) from the prompt",
        "Record any explicit year(s), months, day-of-week mentions, and range boundaries",
        "Normalize tokens (e.g., map weekdays to 0-6; months to 1-12)"
      ],
      "outputs": [
        "state.anchors populated",
        "state.constraints partially populated"
      ]
    },
    {
      "id": 2,
      "name": "Anchoring",
      "actions": [
        "Identify anchor date(s): explicit YYYY-MM-DD if present; otherwise deduce from context (e.g., event-year, holiday-year)",
        "Set state.context.year: choose explicit year if given; else infer from anchors; else leave null",
        "Set state.context.locale: use explicit; else default to US if holidays matter"
      ],
      "outputs": [
        "state.context.year set or null",
        "state.context.locale set"
      ]
    },
    {
      "id": 3,
      "name": "Planning",
      "actions": [
        "List all constraints and relations to be satisfied (day-of-week, holiday placement, relative offsets, nth-weekday, ranges)",
        "Choose a minimal set of anchors to reduce the problem to a single base date plus one clear operation when possible",
        "Establish computation order: compute any required holiday dates or nth-weekday dates first, then apply relative offsets"
      ],
      "outputs": [
        "Ordered list of operations to perform",
        "Simplified anchor and constraint set"
      ]
    },
    {
      "id": 4,
      "name": "Conversion",
      "actions": [
        "Translate relative phrases into numeric operations:",
        "- N days after/before => +/- N days",
        "- next/previous <weekday> => helper next_weekday/previous_weekday",
        "- nth <weekday> of <month> => helper nth_weekday_of_month",
        "- last <weekday> of <month> => nth_weekday_of_month with n = -1",
        "- end of month => (YYYY, MM, month_length)",
        "If holidays are referenced, compute holiday date using compute_holiday_date with state.context.year (if year unknown, branch candidates across plausible years if context allows)"
      ],
      "outputs": [
        "Concrete operations (functions with parameters) ready for computation"
      ]
    },
    {
      "id": 5,
      "name": "Computation",
      "actions": [
        "Apply operations in order with correct month lengths and leap-year rules",
        "Handle rollovers across months/years during arithmetic",
        "Accumulate one or more candidate dates if multiple branches exist (e.g., unknown year)"
      ],
      "outputs": [
        "state.candidates with provisional dates"
      ]
    },
    {
      "id": 6,
      "name": "Validation",
      "actions": [
        "For each candidate date, verify all constraints:",
        "- Day-of-week matches if specified",
        "- Holiday matches target holiday for the computed year/locale",
        "- Lies within any specified range limits",
        "- Satisfies all relative relations against their references",
        "Discard any candidate violating a constraint"
      ],
      "outputs": [
        "Filtered candidates with status validated or discarded"
      ]
    },
    {
      "id": 7,
      "name": "Critical verification",
      "actions": [
        "Recheck leap-year status and month lengths used",
        "Optionally recompute via an alternate path (e.g., recompute weekday or re-derive holiday) to confirm consistency",
        "Ensure every textual clue has been used or is provably irrelevant; if contradictions found, mark inconsistent"
      ],
      "outputs": [
        "Confidence that computations are correct or reasons for inconsistency"
      ]
    },
    {
      "id": 8,
      "name": "Decision",
      "actions": [
        "If exactly one validated candidate remains, set state.final_date",
        "If zero candidates remain due to contradictions, set state.inconsistency_reasons and stop with Inconsistent constraints",
        "If multiple validated candidates remain, set state.ambiguity_reasons and stop with Ambiguous"
      ],
      "outputs": [
        "Single final date or an ambiguity/inconsistency status"
      ]
    },
    {
      "id": 9,
      "name": "Formatting",
      "actions": [
        "If state.final_date is set (YYYY-MM-DD), output as MM/DD/YYYY zero-padded",
        "If ambiguous, output \"Ambiguous\" followed by a brief reason list",
        "If inconsistent, output \"Inconsistent constraints.\""
      ],
      "outputs": [
        "Single string per output_spec"
      ]
    }
  ],
  "edge_handling": {
    "year_missing": "If year cannot be inferred after Planning, branch over plausible years only if context limits them; otherwise mark Ambiguous",
    "multiple_anchors_conflict": "Prefer the most explicit date anchor; if conflicts persist after validation, mark Inconsistent constraints",
    "range_cross_year": "Allow offsets to roll over year boundaries",
    "locale_for_holidays": "If unspecified but holidays are essential, default to US federal definitions"
  },
  "holiday_rules_us_federal_summary": {
    "New Year’s Day": "Jan 1 (observed rules may shift weekdays; use actual date unless problem states observed)",
    "MLK Day": "3rd Monday of January",
    "Presidents’ Day": "3rd Monday of February",
    "Memorial Day": "Last Monday of May",
    "Juneteenth": "June 19",
    "Independence Day": "July 4",
    "Labor Day": "1st Monday of September",
    "Columbus/Indigenous Peoples’ Day": "2nd Monday of October",
    "Veterans Day": "November 11",
    "Thanksgiving": "4th Thursday of November",
    "Christmas": "December 25"
  },
  "output_spec": {
    "success": "Exactly one final date in MM/DD/YYYY with zero-padded month/day and four-digit year, no extra text",
    "ambiguous": "Output the word \"Ambiguous\" followed by a concise reason (e.g., missing year; multiple valid anchors)",
    "inconsistent": "Output exactly: \"Inconsistent constraints.\""
  },
  "stop_condition": "Stop when a single unambiguous, validated date is obtained or when ambiguity/inconsistency is determined."
}

