  "purpose": "Step-by-step reasoning plan to solve 5-item linear ordering puzzles with positional constraints.",
  "assumptions": [
    "Five distinct items; positions are linear 1–5 (left to right); one item per position.",
    "Before/after is strict (< or >).",
    "Immediately means distance exactly 1 (|dx| = 1).",
    "Not next to means distance not equal to 1 (|dx| != 1).",
    "k before/after means exact offset k (|dx| = k with sign).",
    "Leftmost/rightmost means position 1 or 5 respectively.",
    "Between X and Y means strictly between positions of X and Y (order of X/Y unspecified unless stated).",
    "Arrangement is not circular; fixed left-to-right orientation.",
    "Prefer strictest standard logic-puzzle interpretations if ambiguous."
  ],
  "normalization_rules": [
    "Label positions 1..5 from left to right.",
    "Translate language: before/left of -> <; after/right of -> >.",
    "Translate immediately before/after -> distance = 1.",
    "Translate 'k before/after' -> absolute offset k with direction.",
    "Translate 'between' -> strict inequality min(P(X), P(Y)) < P(Z) < max(P(X), P(Y)).",
    "Translate 'not next to' -> distance != 1.",
    "Exploit mirror symmetry if no rule anchors to positions 1 or 5: pick canonical orientation."
  ],
  "schemas": {
    "constraint_types": [
      {
        "type": "order",
        "fields": ["less", "greater"],
        "meaning": "P(less) < P(greater)"
      },
      {
        "type": "offset",
        "fields": ["first", "second", "k", "direction"],
        "meaning": "If direction='before': P(first) = P(second) - k; if 'after': P(first) = P(second) + k"
      },
      {
        "type": "adjacent",
        "fields": ["a", "b"],
        "meaning": "|P(a) - P(b)| = 1"
      },
      {
        "type": "not_adjacent",
        "fields": ["a", "b"],
        "meaning": "|P(a) - P(b)| != 1"
      },
      {
        "type": "end",
        "fields": ["item", "position"],
        "meaning": "P(item) = 1 or 5"
      },
      {
        "type": "absolute",
        "fields": ["item", "position"],
        "meaning": "P(item) = fixed position in {1..5}"
      },
      {
        "type": "between",
        "fields": ["middle", "end1", "end2"],
        "meaning": "min(P(end1), P(end2)) < P(middle) < max(P(end1), P(end2))"
      }
    ],
    "input": {
      "items": ["A", "B", "C", "D", "E"],
      "constraints": [
