stage1.reasoning_structure:
{
  "version": "1.0",
  "purpose": "A step-by-step reasoning plan to solve 5-item linear ordering puzzles (positions 1–5) or answer targeted questions about the order.",
  "assumptions": {
    "domain": "Five unique items placed in a single linear order with positions 1–5 (left-to-right or earliest-to-latest).",
    "no_ties": true,
    "one_item_per_position": true,
    "one_position_per_item": true
  },
  "definitions": {
    "orientation": "Use a canonical orientation: positions increase left-to-right or earliest-to-latest. All constraints refer to this orientation.",
    "clue_semantics": {
      "before_after": "X before Y means position(X) < position(Y).",
      "immediate": "Immediately before/after means distance of exactly 1 in that direction.",
      "exactly_n_between": "Exactly n items between X and Y means |position(X) - position(Y)| = n + 1.",
      "between": "X between Y and Z (order unspecified) means position(Y) < position(X) < position(Z) OR position(Z) < position(X) < position(Y).",
      "position_k": "X at position k fixes position(X) = k."
    },
    "symmetry_breaking": "If symmetric (only relative order matters), optionally fix one reference item to the earliest position it can legally occupy to reduce branching.",
    "objective_types": [
      "full_order",
      "targeted_relation"
    ]
  },
  "input_interface": {
    "items": ["A", "B", "C", "D", "E"],
    "positions": [1, 2, 3, 4, 5],
    "question": {
      "type": "full_order or targeted_relation",
      "prompt": "E.g., 'What is the full order?' or 'Is A before C?' or 'Which item is third?'"
    },
    "clues": [
      "Verbatim natural-language clues to be formalized below."
    ],
    "constraints_formal": [
      {
        "type": "at_position",
        "item": "X",
        "pos": 3
      },
      {
        "type": "before",
        "first": "X",
        "second": "Y"
      },
      {
        "type": "adjacent",
        "first": "X",
        "second": "Y",
        "direction": "before_or_after",
        "distance": 1
      },
      {
        "type": "distance",
        "item1": "X",
        "item2": "Y",
        "gaps": 2
      },
      {
        "type": "between",
        "middle": "X",
        "bounds": ["Y", "Z"],
        "immediate": false
      }
    ]
  },
  "state_structures": {
    "orientation": "left_to_right",
    "matrix": "items x positions boolean grid; true means item can be at position.",
    "placements": {
      "fixed_positions": {},
      "locked_relations": []
    },
    "graphs": {
      "precedence": "Directed edges first->second for 'before' constraints.",
      "transitive_closure": "Computed reachability for earliest/latest windows."
    },
    "derived": {
      "earliest_latest_windows": {
        "item": {
          "earliest": 1,
          "latest": 5
        }
      },
      "parity": "Optional constraints: item must be on odd/even positions due to exact distances.",
      "adjacency_windows": [],
      "exclusions": []
    },
    "logging": [
      "Each elimination/placement annotated with rationale and source clue."
    ],
    "cases": [
      {
        "assumption": "Optional branching assumption",
        "state_snapshot": "Copy of matrix/graphs/placements at branch start"
      }
    ]
  },
  "procedure": [
    {
      "step": 1,
      "name": "Identify core objective",
      "actions": [
        "Record whether the goal is a full order or a specific relation/position question.",
        "Confirm domain: 5 distinct items, positions 1–5, linear order, no ties."
      ],
      "outputs": [
        "objective_type",
        "validated domain assumptions"
      ]
    },
    {
      "step": 2,
      "name": "Normalize and standardize clues",
      "actions": [
        "Relabel positions 1–5 with chosen orientation.",
        "Ensure all items are uniquely identified.",
        "Translate each natural-language clue into atomic formal constraints using the allowed types.",
        "Clarify ambiguous terms: distinguish 'between' from 'immediately between', confirm whether distances are exact."
      ],
      "checks": [
        "Reject hidden assumptions (e.g., adjacency transitivity).",
        "Where helpful and symmetry allows, fix one reference item to its earliest legal position to reduce branching."
      ]
    },
    {
      "step": 3,
      "name": "Initialize possibility matrix",
      "actions": [
        "Create items x positions grid initialized to true.",
        "Apply base rules (one item per position; one position per item)."
      ],
      "updates": [
        "matrix: all true",
        "graphs.precedence: empty"
      ]
    },
    {
      "step": 4,
      "name": "Apply strongest direct constraints",
      "actions": [
        "Fixed positions: for each at_position(X,k), set matrix[X,*]=false except k=true; eliminate column k for all other items.",
        "Immediate adjacency: for 'X immediately before Y', restrict X to positions 1–4 with Y at X+1; for 'after', restrict Y accordingly; update matrix to only those pairs.",
        "Exact distances: for distance constraints (n gaps), restrict pairs to positions differing by n+1; apply parity implications (opposite parity if n is even/odd as appropriate).",
        "Between (order unknown): if X between Y and Z, ensure X is not at extremes; Y and Z must occupy one on each side of X; restrict windows for all three accordingly.",
        "Before/after: add edges to precedence graph; rule out impossible extremes (e.g., if X before Y, X cannot be at position 5; Y cannot be at position 1)."
      ],
      "updates": [
        "matrix pruned",
        "graphs.precedence updated"
      ]
    },
    {
      "step": 5,
      "name": "Propagate uniqueness and closures",
      "actions": [
        "Row singletons: if an item has only one possible position, place it; clear that column for others.",
        "Column singletons: if a position admits only one item, place that item there.",
        "Precedence closure: compute transitive closure; tighten earliest/latest windows for each item using graph order and fixed placements."
      ],
      "loop": "Iterate steps 4–5 until no further changes."
    },
    {
      "step": 6,
      "name": "Derive secondary implications",
      "actions": [
        "Parity deductions from exact distances; remove positions of disallowed parity.",
        "Spacing chains: combine distances and precedence (e.g., if A is two before B and B before C, derive earliest/latest windows for C).",
        "Adjacency conflicts: if two adjacency requirements overlap impossibly, eliminate cases.",
        "Test each new deduction by attempting a counterexample; if any counterexample is consistent, do not lock the deduction."
      ],
      "loop": "Re-run uniqueness propagation after any new elimination."
    },
    {
      "step": 7,
      "name": "Minimal branching if unresolved",
      "precondition": "Matrix not fully resolved and the objective not yet answered.",
      "strategy": "Choose the tightest uncertain choice to branch on.",
      "choice_heuristics": [
        "Pick an item row with the fewest remaining positions (>1).",
        "Or select a high-impact relation (e.g., which side of a 'between' or a specific adjacency placement)."
      ],
      "actions": [
        "Create case nodes: for each candidate option, record an assumption (e.g., position(X)=k).",
        "Within each case: copy current state; apply the assumption; resume steps 4–6.",
        "If a contradiction occurs (empty row/column or edge violation), discard the case (backtrack)."
      ],
      "termination": "Stop branching when the objective is determined or a full consistent order is obtained for all surviving cases."
    },
    {
      "step": 8,
      "name": "Validate solutions and consistency",
      "actions": [
        "For each surviving case/solution, check every formal constraint against the constructed order.",
        "Reject any solution violating any clue."
      ],
      "outputs": [
        "set_of_solutions (could be one or multiple)"
      ]
    },
    {
      "step": 9,
      "name": "Answer extraction and uniqueness",
      "actions": [
        "If objective is full_order: report the unique order; if multiple, report all or state non-uniqueness.",
        "If objective is targeted_relation: extract the invariant that holds across all surviving solutions; if answers differ, report that it cannot be determined uniquely and provide the range/alternatives."
      ],
      "checks": [
        "Ensure the reported answer is justified by constraints, not assumptions outside the model."
      ]
    }
  ],
  "inference_patterns": {
    "earliest_latest_window_update": "Use precedence chain A<B<C to tighten: earliest(C) >= 1 + count_of_predecessors(C); latest(A) <= 5 - count_of_successors(A).",
    "distance_window_update": "If |pos(X) - pos(Y)| = n+1, then earliest(X) >= earliest(Y) - (n+1) and <= latest(Y) - (n+1), similarly mirrored.",
    "between_restrictions": "If X between Y and Z, then earliest(X) >= 2 and latest(X) <= 4; and Y,Z cannot both be on the same side of X.",
    "adjacency_windows": "If X immediately before Y, then X ∈ {1..4}, Y = X+1; remove Y from position 1 and X from position 5."
  },
  "branching_management": {
    "case_stack": [
      {
        "id": "case_id",
        "assumption": "e.g., B at position 3",
        "parent": "optional_parent_case_id",
        "state_snapshot": "serialized matrix/graphs/placements",
        "status": "open/resolved/contradiction"
      }
    ],
    "pruning_rules": [
      "If any item row has zero possible positions, mark contradiction.",
      "If precedence graph forms a cycle, mark contradiction.",
      "If distance/adjacency windows produce no feasible placements, mark contradiction."
    ]
  },
  "verification": {
    "consistency_checks": [
      "Every item placed exactly once; every position filled exactly once.",
      "All 'before' edges hold in final order.",
      "All adjacency and distance relations hold exactly as specified.",
      "All 'between' semantics satisfied in one of the two internal orders."
    ],
    "non_uniqueness_detection": "If more than one solution remains consistent post-verification, mark non-unique and compute invariant answers for targeted questions."
  },
  "output_interface": {
    "solution_format": {
      "full_order": ["pos1_item", "pos2_item", "pos3_item", "pos4_item", "pos5_item"],
      "targeted_relation": {
        "query": "original question",
        "answer": "e.g., 'A is before C' or 'Cannot be determined uniquely'",
        "invariant_evidence": "brief rationale or common relation across all solutions"
      }
    },
    "uniqueness": "unique | multiple",
    "explanatory_log": "Ordered list of deductions with references to clue IDs and justification."
  },
  "execution_guidelines": {
    "apply_strongest_first": "Prioritize fixed positions, extremes, and immediate adjacency/distance constraints before softer precedence chains.",
    "iterate_pruning": "After any update, re-run singleton and window tightening.",
    "critical_thinking": [
      "Do not assume internal order of 'between' unless specified.",
      "Adjacency is not transitive.",
      "Parities from exact distances are often decisive; enforce them early.",
      "Attempt small counterexamples to test whether a deduction is truly forced."
    ],
    "stop_conditions": [
      "Full order determined and validated.",
      "Targeted question invariant determined across all consistent solutions."
    ]
  }
}

