  "purpose": "Solve five-object linear ordering (constraint) puzzles step-by-step and verify the result.",
  "assumptions": {
    "objects_are_distinct": true,
    "positions": [1, 2, 3, 4, 5],
    "ends": [1, 5],
    "one_based_indexing": true,
    "orientation": "1 is leftmost/first; 5 is rightmost/last",
    "before_after_is_strict": true,
    "immediately_means_distance_1": true,
    "between_is_strict": true,
    "ambiguity_policy": "If any wording is ambiguous, record interpretation here before solving."
  },
  "notation": {
    "A@k": "Object A is at position k",
    "A<B": "A is somewhere before B",
    "|A−B|=1": "A and B are adjacent (unordered)",
    "A⋖B": "A is immediately before B (ordered adjacency)",
    "dist(A,B)=d": "The distance between A and B is d (|pos(A)−pos(B)|=d)",
    "between(X,Y,Z)": "Y is strictly between X and Z (two linear cases: X<Y<Z or Z<Y<X)"
  },
  "input_schema": {
    "objects": ["A", "B", "C", "D", "E"],
    "clues_text": ["List of natural-language clues here"],
    "constraints": [
      {
        "id": "c1",
        "type": "fixed",
        "obj": "A",
        "pos": 3
      },
      {
        "id": "c2",
        "type": "order",
        "left": "B",
        "right": "C"
      },
      {
        "id": "c3",
        "type": "adjacent",
        "pair": ["D", "E"],
        "ordered": false
      },
      {
        "id": "c4",
        "type": "adjacent_ordered",
        "left": "A",
        "right": "B"
      },
      {
        "id": "c5",
        "type": "distance",
        "pair": ["C", "D"],
        "dist": 2,
        "negated": false
      },
      {
        "id": "c6",
        "type": "between",
        "outer": ["A", "E"],
        "middle": "C",
        "inclusive": false
      },
      {
        "id": "c7",
        "type": "end",
        "obj": "B",
        "allowed": [1, 5]
      },
      {
        "id": "c8",
        "type": "not_positions",
        "obj": "D",
        "positions": [1, 5]
      },
      {
        "id": "c9",
        "type": "not_adjacent",
        "pair": ["A", "D"]
      },
      {
        "id": "c10",
        "type": "or",
        "options": [
          { "type": "order", "left": "A", "right": "D" },
          { "type": "order", "left": "E", "right": "B" }
        ]
      }
    ]
  },
  "data_structures": {
    "state": {
      "objects": [],
      "positions": [1, 2, 3, 4, 5],
      "domains": { "A": [1, 2, 3, 4, 5], "B": [1, 2, 3, 4, 5] },
      "position_candidates": { "1": [], "2": [], "3": [], "4": [], "5": [] },
      "assigned": { "1": null, "2": null, "3": null, "4": null, "5": null },
      "constraints": [],
      "derived_relations": {
        "order_chains": [],
        "adjacency_blocks": [],
        "not_adjacent_pairs": [],
        "end_restrictions": []
      },
      "branch_stack": [],
      "logs": []
    }
  },
  "workflow": [
    {
      "step": 1,
      "name": "Setup and Clarify",
      "actions": [
        "Record objects and positions [1..5].",
        "Confirm assumptions and any needed interpretation (e.g., 'between' is strict).",
        "Initialize domains[obj] = [1,2,3,4,5] for each object.",
        "Initialize assigned[1..5] = null."
      ],
      "checks": ["No duplicate objects.", "Positions are exactly [1,2,3,4,5]."]
    },
    {
      "step": 2,
      "name": "Normalize Clues to Constraints",
      "actions": [
        "Translate each clue into one or more standard constraints using the notation.",
        "Categorize each as: fixed, order, adjacent, adjacent_ordered, distance, between, not_positions, not_adjacent, end, or disjunction (or).",
        "For 'immediately before/after' add both order and adjacency (ordered) constraints.",
        "For 'one of the ends' add end constraint with allowed [1,5].",
        "For 'between' keep as a two-case constraint (do not prematurely pick a side)."
      ],
      "checks": ["Each clue represented; record the mapping from text to formal constraint ids."]
    },
    {
      "step": 3,
      "name": "Seed Candidates and Quick Pruning",
      "actions": [
        "Apply fixed and end constraints to prune domains.",
        "Apply obvious exclusions from adjacency/distance near ends (e.g., if A⋖B then A≠5 and B≠1).",
        "Populate position_candidates[pos] with objects still allowed at pos."
      ],
      "checks": ["All domains non-empty after initial pruning."]
    },
    {
      "step": 4,
      "name": "Deterministic Propagation Loop",
      "loop": true,
      "actions": [
        "Repeat until no change:",
        "- Enforce order constraints: if A<B, then max(dom(A)) < max(pos) and min(dom(B)) > min(pos) as implied; prune impossible positions accordingly; propagate transitivity.",
        "- Enforce adjacency (unordered): restrict pairs of positions for the pair; remove positions that cannot be matched with a neighbor.",
        "- Enforce ordered adjacency (A⋖B): restrict to pairs (1,2),(2,3),(3,4),(4,5); prune A∉{5}, B∉{1}; remove any positions where the counterpart cannot fit.",
        "- Enforce distance: prune any positions where the partner cannot be at the required distance.",
        "- Enforce not_adjacent: remove positions that would force adjacency.",
        "- Enforce not_positions: delete listed positions from the domain.",
        "- Enforce end: intersect domain with [1,5] or its complement as given.",
        "- Merge and extend order chains via transitivity (A<B and B<C => A<C).",
        "- For each position, if only one object can fit, assign it; for each object, if only one position remains, assign it.",
        "- After each assignment, remove the object from other positions and remove the position from other objects' domains."
      ],
      "checks": [
        "After each pruning or assignment, run consistency scan: no empty domains, no violated constraints."
      ]
    },
    {
      "step": 5,
      "name": "Edge Testing",
      "actions": [
        "Test plausibility of placing highly-constrained items at ends (1 or 5).",
        "If placing an item at an end leads to immediate contradiction via propagation, forbid that end for the item."
      ],
      "checks": ["Record each test as a reversible assumption if branching is used."]
    },
    {
      "step": 6,
      "name": "Resolve 'Between' Constraints",
      "actions": [
        "For each unresolved between(X,Y,Z), consider two linear cases: X<Y<Z and Z<Y<X.",
        "If one case contradicts current domains/assignments, eliminate it.",
        "If both remain feasible and no progress, defer to branching."
      ]
    },
    {
      "step": 7,
      "name": "Forced Placements",
      "actions": [
        "Scan for singletons: object with one remaining position or position with one candidate object.",
        "Commit forced placements and propagate (return to Step 4)."
      ]
    },
    {
      "step": 8,
      "name": "Branch on Smallest Ambiguity (if needed)",
      "actions": [
        "Select the object with the smallest domain (>1) or the tightest unresolved 'between'/'or' case.",
        "Push a branch frame: record assumption, snapshot of domains/assignments, and pending alternative(s).",
        "Commit the assumption (e.g., A@k or pick one between-case) and return to Step 4.",
        "On contradiction, pop and try the next alternative; if none remain, backtrack further."
      ],
      "heuristics": [
        "Smallest-domain-first.",
        "Prefer resolving structured constraints ('between', ordered adjacency) before generic guesses.",
        "Apply symmetry breaking: if the entire constraint set is mirror-symmetric and no end is specified, fix a representative orientation (e.g., the alphabetically first object occurs before the alphabetically last)."
      ]
    },
    {
      "step": 9,
      "name": "Validate and Conclude",
      "actions": [
        "When all positions are assigned, verify against every original clue.",
        "If multiple solutions remain and the question asks for a specific feature (e.g., who is first), report the guaranteed feature across all solutions; otherwise, list all valid orders."
      ],
      "outputs": [
        "final_order: array of objects from position 1 to 5 (if unique).",
        "all_solutions: list of all valid orders if multiple.",
        "explanation_log: sequence of inferences and their source constraints."
      ]
    }
  ],
  "propagation_rules": [
    {
      "name": "Order pruning (A<B)",
      "effect": "For each pos in dom(A), require existence of some pos' in dom(B) with pos<pos'; delete pos if none. Similarly for dom(B), require some pos'<pos in dom(A); delete pos if none."
    },
    {
      "name": "Adjacency unordered (|A−B|=1)",
      "effect": "For each pos in dom(A), retain only if pos±1 intersects dom(B); mirror for dom(B). Ends: A cannot be at 1 if B cannot be at 2, etc."
    },
    {
      "name": "Ordered adjacency (A⋖B)",
      "effect": "Restrict to pairs (1,2),(2,3),(3,4),(4,5); A∉{5}, B∉{1}; prune positions where the counterpart cannot occupy the immediately following/preceding slot."
    },
    {
      "name": "Distance exact (dist(A,B)=d)",
      "effect": "For each pos in dom(A), retain only if pos±d intersects dom(B); mirror for dom(B)."
    },
    {
      "name": "Not adjacent",
      "effect": "Delete any pos in dom(A) for which only adjacent placements of B remain and vice versa; ensure at least one non-adjacent option for each."
    },
    {
      "name": "Fixed/end/not_positions",
      "effect": "Intersect domains with allowed sets or remove forbidden positions; set assignments for fixed."
    },
    {
      "name": "Transitivity",
      "effect": "Maintain and extend chains A<B, B<C => A<C; use to prune min/max feasible positions."
    },
    {
      "name": "Only-fit detection",
      "effect": "If a position has only one candidate object or an object has only one candidate position, assign it."
    }
  ],
  "tactics": [
    "Constraint propagation (domain pruning).",
    "End-spot testing (try 1 or 5 early for constrained items).",
    "Chain building and merging for < relations.",
    "Adjacency block placement and sliding windows.",
    "Distance feasibility against remaining slots.",
    "Spot the 'only fit' for a position or object.",
    "Case split on the smallest domain; backtrack on contradiction.",
    "Symmetry breaking when mirror images are equivalent."
    ]
  ,
  "branching": {
    "selection": "smallest-domain-first",
    "record": {
      "assumption": "What is being assumed (e.g., A@2, or X<Y<Z in a between-case).",
      "state_snapshot": "Copy of domains, assignments, pending constraints.",
      "contradiction_signature": "Which rule/clue caused failure to prune future branches."
    },
    "backtrack": "On contradiction, restore snapshot and try the next alternative; if none left, bubble up."
  },
  "validation": {
    "consistency_scan": [
      "No domain is empty.",
      "No two objects share a position.",
      "Every assignment respects all constraints."
    ],
    "edge_tests": [
      "Confirm ends are feasible for items allowed at ends.",
      "Distinguish 'before' vs 'immediately before', 'next to' vs 'near', inclusive vs strict 'between' per assumptions."
    ],
    "final_check": "Evaluate the completed order against every original clue text-to-constraint mapping."
  },
  "termination": {
    "unique_solution": "All 5 positions assigned with no contradictions and no untried branches remain.",
    "multiple_solutions": "At least two distinct complete assignments satisfy all constraints; report as required.",
    "unsatisfiable": "All branches exhausted with contradictions; report no solution with the conflict log."
  },
  "output_schema": {
    "status": "one_of: ['unique', 'multiple', 'unsatisfiable', 'partial_feature_resolved']",
    "final_order": ["pos1_obj", "pos2_obj", "pos3_obj", "pos4_obj", "pos5_obj"],
    "all_solutions": [["..."], ["..."]],
    "feature_answer": "If the puzzle only asks for a specific position/object feature.",
    "logs": [
      {
        "step": "e.g., propagation",
        "rule": "e.g., Ordered adjacency",
        "source_constraints": ["c4"],
        "inference": "e.g., A≠5, B≠1; A@2 eliminated",
        "resulting_domains": { "A": [1, 2, 3], "B": [2, 3, 4, 5] }
      }
    ]
  }
}

