      "weeks_after": "Exclusive; add X*7 days.",
      "before_after_months": "Use month offsets; see month_offset_policy."
    },
    "next_last_weekday": {
      "next": "Strictly after the reference date; if the reference date is that weekday, move +7 days.",
      "last": "Strictly before the reference date; if the reference date is that weekday, move -7 days."
    },
    "nth_weekday": {
      "rule": "Compute first weekday of month, then advance by (n−1)*7 days.",
      "nonexistent": "Flag impossibility if nth occurrence falls outside the month."
    },
    "year_resolution": "If any anchor includes a year, use that year for all derived dates unless a different year is explicitly stated; otherwise infer from context or request clarification.",
