    "date_units": "Standardize on days/weeks/months; ignore time-of-day unless it affects inclusive/exclusive counting.",
    "month_offset_policy": "Preserve day-of-month when adding months; if the target month lacks that day, default to clamping to the last day of that month and mark as potentially ambiguous."
  },
  "step_sequence": [
    {
      "id": "parse",
      "description": "Extract all date-related tokens and constraints.",
      "actions": [
        "Identify explicit dates (month/day/year).",
        "Extract months, weekdays, ordinals (1st..5th), and numbers.",
        "Detect relative terms: before, after, next, last, in X days/weeks/months, on the Xth day.",
        "Record any explicit anchor dates or implied anchors.",
        "Normalize numeric words to integers (e.g., 'three' -> 3).",
        "List all statements as raw constraints."
      ],
      "outputs": [
        "tokens",
        "constraints_raw"
      ]
    },
    {
      "id": "select_anchor",
      "description": "Choose the single anchor date to minimize computation steps.",
      "rules": [
        "Prefer an explicit full date with year.",
        "If multiple, choose the one yielding the fewest subsequent operations.",
        "If only partial dates exist but one has a resolvable year, use it.",
        "Do not assume 'today/this year' unless explicitly provided."
      ],
      "outputs": [
        "anchor_date",
        "anchor_evidence"
      ]
    },
    {
      "id": "normalize_constraints",
      "description": "Convert all language into precise arithmetic or weekday rules relative to the anchor.",
      "actions": [
        "Translate 'X days/weeks after/before' into signed day offsets (weeks = 7*X).",
        "Map 'next/last <weekday>' to strict-after/strict-before weekday rules.",
        "Convert 'nth <weekday> of <month>' to a month+weekday+ordinal constraint with a resolved year.",
        "Reduce multi-step chains into a single net operation when order is commutative.",
        "Keep only essentials: numbers, weekdays, months, ordinals, relative terms."
      ],
      "outputs": [
        "constraints"
      ]
    },
    {
      "id": "compute",
      "description": "Apply deterministic calendar arithmetic to produce candidate dates.",
      "substeps": [
        {
          "id": "apply_offsets",
          "when": "Constraint is an absolute day/week offset.",
          "method": "target = addDays(reference_date, offset_days)."
        },
        {
          "id": "weekday_target_next",
          "when": "Constraint is 'next <weekday>' from a reference date.",
          "method": "delta = (w - weekday(ref) + 7) % 7; if delta == 0 then delta = 7; target = addDays(ref, delta)."
        },
        {
          "id": "weekday_target_last",
          "when": "Constraint is 'last <weekday>' from a reference date.",
          "method": "delta = (weekday(ref) - w + 7) % 7; if delta == 0 then delta = 7; target = addDays(ref, -delta)."
        },
        {
          "id": "nth_weekday_in_month",
          "when": "Constraint is 'nth <weekday> of <month>'.",
          "method": "first = date(Y, M, 1); delta = (w - weekday(first) + 7) % 7; first_hit = addDays(first, delta); candidate = addDays(first_hit, 7*(n-1)); if month(candidate) != M then nonexistent."
        },
        {
          "id": "month_offsets",
          "when": "Constraint includes month-based shifts.",
          "method": "target = addMonths(reference_date, m); preserve D; if D exceeds daysInMonth(Y2, M2), clamp to month end and flag ambiguity."
        }
      ],
      "outputs": [
        "candidate_dates"
      ]
    },
    {
      "id": "reconcile",
      "description": "Intersect results from multiple constraints to isolate the single valid date.",
      "actions": [
        "Generate candidate sets per independent constraint.",
        "Intersect sets to find common dates.",
