        "validated_date",
        "issues"
      ]
    },
    {
      "id": "cross_verify",
      "description": "Double-check via an alternative calculation path.",
      "methods": [
        "Confirm weekday computations via modulo-7 and by direct counting from a calendar.",
        "If multiple anchors were available, recompute from an alternate anchor to ensure the same result."
      ],
      "outputs": [
        "verification_status"
      ]
    },
    {
      "id": "ambiguity_resolution",
      "description": "Identify and handle ambiguities or conflicts.",
      "actions": [
        "Default 'next/last' to strict-after/strict-before; note this assumption.",
        "If 'on the Xth day' ambiguity affects result, request clarification.",
