      ],
      "outputs": [
        "final_assumptions",
        "conflict_report"
      ]
    },
    {
      "id": "format_output",
      "description": "Produce the final date.",
      "rules": [
        "Exactly one date must remain after reconciliation and validation.",
        "Format as MM/DD/YYYY with zero-padded month and day."
      ],
      "outputs": [
        "MM/DD/YYYY"
      ]
    }
  ],
  "algorithms": {
    "weekday_numbering": {
      "Sunday": 0,
      "Monday": 1,
      "Tuesday": 2,
      "Wednesday": 3,
      "Thursday": 4,
      "Friday": 5,
      "Saturday": 6
    },
    "addDays": "Given date d(Y,M,D) and integer n, return the date n days after d (n may be negative).",
    "weekday": "Return 0..6 per weekday_numbering for a given date; use a standard algorithm or library.",
    "daysUntilNextWeekday": "delta = (w - weekday(r) + 7) % 7; if delta == 0 then delta = 7; return delta.",
    "daysSinceLastWeekday": "delta = (weekday(r) - w + 7) % 7; if delta == 0 then delta = 7; return delta.",
    "nthWeekdayOfMonth": "first = date(Y,M,1); delta = (w - weekday(first) + 7) % 7; first_hit = addDays(first, delta); candidate = addDays(first_hit, 7*(n-1)); if month(candidate) != M then nonexistent else candidate.",
    "addMonths": "Given d(Y,M,D) and integer m: M2 = M + m; Y2 = Y + floor((M2-1)/12); M2 = ((M2-1) % 12) + 1; D2 = min(D, daysInMonth(Y2,M2)); return (Y2,M2,D2).",
    "daysInMonth": "For M in {1,3,5,7,8,10,12} return 31; {4,6,9,11} return 30; for 2 return 29 if isLeapYear(Y) else 28.",
    "isLeapYear": "Y is leap if (Y % 4 == 0 and Y % 100 != 0) or (Y % 400 == 0)."
  },
  "data_structures": {
    "date": {
      "year": "integer",
      "month": "1-12",
      "day": "1-31 subject to month length"
    },
    "constraint": {
      "type": "offset_days | next_weekday | last_weekday | nth_weekday_of_month | month_offset | absolute_date",
      "parameters": "e.g., {days: int} or {weekday: 0-6} or {n: int, weekday: 0-6, month: 1-12, year: int}",
      "reference_date": "date used as the starting point for this constraint (often the anchor)"
    }
  },
