stage1.reasoning_structure:
{
  "plan_name": "Five-Object Ordering Puzzle Solver (CSP with propagation and backtracking)",
  "purpose": "Given five objects and textual constraints, deduce the full left-to-right order or answer a targeted relationship query.",
  "orientation_and_assumptions": {
    "positions": [1, 2, 3, 4, 5],
    "orientation": "1 = leftmost, 5 = rightmost",
    "one_per_position": true,
    "distinct_objects": true,
    "adjacency_def": "next to means |pos(A) - pos(B)| = 1",
    "immediately_def": "immediately left/right means distance = 1 with direction",
    "between_def": "exclusive between unless text explicitly says inclusive; A between X and Y means min(pos(X), pos(Y)) < pos(A) < max(pos(X), pos(Y))",
    "either_end_def": "positions {1,5}",
    "ambiguity_policy": "Adopt standard interpretations above; if puzzle wording conflicts, flag and adjust."
  },
  "normalization_map": {
    "immediately to the left of": "pos(A) = pos(B) - 1",
    "immediately to the right of": "pos(A) = pos(B) + 1",
    "next to": "|pos(A) - pos(B)| = 1",
    "not next to": "|pos(A) - pos(B)| != 1",
    "to the left of": "pos(A) < pos(B)",
    "to the right of": "pos(A) > pos(B)",
    "at the left end": "pos(A) = 1",
    "at the right end": "pos(A) = 5",
    "at an end": "pos(A) in {1,5}",
    "not at an end": "pos(A) in {2,3,4}",
    "between X and Y": "min(pos(X), pos(Y)) < pos(A) < max(pos(X), pos(Y))",
    "exact position k": "pos(A) = k"
  },
  "constraint_forms": [
    "pos(A) = k",
    "pos(A) != k",
    "pos(A) in S",
    "pos(A) < pos(B)",
    "pos(A) > pos(B)",
    "|pos(A) - pos(B)| = 1",
    "|pos(A) - pos(B)| != 1",
    "pos(A) = pos(B) - 1",
    "pos(A) = pos(B) + 1",
    "pos(A) between B and C"
  ],
  "inputs": {
    "objects": [],
    "constraints_nl": [],
    "question": "full_order or specific_relation"
  },
  "state": {
    "domains": {},
    "grid": {},
    "constraints": [],
    "order_chains": [],
    "adjacency_requirements": [],
    "exclusions": [],
    "anchors": [],
    "logs": [],
    "decision_stack": [],
    "solutions": []
  },
  "propagation_rules": [
    {
      "name": "Immediate Left/Right Ends",
      "trigger": "pos(A) = pos(B) - 1 or pos(A) = pos(B) + 1",
      "effect": "Eliminate pos(A)=5 for left-of; eliminate pos(B)=1 for left-of; symmetrically for right-of."
    },
    {
      "name": "Adjacency Near Ends",
      "trigger": "|pos(A) - pos(B)| = 1",
      "effect": "If pos(A) in {1}, then pos(B) in {2}; if pos(A) in {5}, pos(B) in {4}; propagate symmetrically."
    },
    {
      "name": "Non-Adjacency",
      "trigger": "|pos(A) - pos(B)| != 1",
      "effect": "Remove positions for A that are adjacent to any feasible position of B and vice versa."
    },
    {
      "name": "Between Bounds",
      "trigger": "A between B and C",
      "effect": "A cannot be at {1,5}; A’s domain subset of {2,3,4}. If B at k and C at m, enforce min(k,m) < pos(A) < max(k,m)."
    },
    {
      "name": "Order Chain Merge",
      "trigger": "pos(A) < pos(B), pos(B) < pos(C), ...",
      "effect": "Merge to A < B < C < ...; bound chain positions (a chain of length L must occupy a contiguous block of length L within 1..5)."
    },
    {
      "name": "Mutual Exclusion",
      "trigger": "one-per-position",
      "effect": "When pos(A) = k, remove k from all other domains; when pos(A) != k for all but one A, assign remaining."
    },
    {
      "name": "End Constraints",
      "trigger": "at an end / not at an end",
      "effect": "Restrict domains to {1,5} or {2,3,4} accordingly."
    },
    {
      "name": "Chain Feasibility Pruning",
      "trigger": "long chains near ends",
      "effect": "If A < B < C cannot fit to the right of a fixed end placement, eliminate conflicting positions."
    },
    {
      "name": "Consistency Check",
      "trigger": "any update",
      "effect": "If any domain becomes empty, raise contradiction for backtracking."
    }
  ],
  "branching_strategy": {
    "selection": "Minimum Remaining Values (MRV): choose object with the smallest domain size > 1",
    "value_ordering": "Try positions in ascending order; prefer positions that satisfy immediate/adjacent constraints first",
    "backtracking": "On contradiction, revert last decision and try next value; continue until solution or exhaustion",
    "symmetry_breaking": "Keep left-to-right orientation fixed; if puzzle admits mirror symmetry and not otherwise broken, note multiple solutions"
  },
  "fallback_bruteforce": {
    "when_to_use": "For verification or if propagation stalls",
    "method": "Enumerate all 120 permutations; prune early using constraints; collect all satisfying orders; compare with propagation results"
  },
  "steps": [
    {
      "id": 1,
      "title": "Transcribe and Normalize",
      "objective": "Extract objects and convert natural-language constraints into formal pos-constraints",
      "procedure": [
        "List the five distinct objects; verify count = 5",
        "Map each textual statement via normalization_map into constraint_forms",
        "Flag any ambiguity (e.g., inclusive between); resolve using assumptions or note explicitly"
      ],
      "outputs": [
        "state.constraints (formalized)",
        "state.anchors (ends, immediate relations, fixed positions)",
        "objects list"
      ],
      "checks": [
        "No duplicate object names",
        "All referenced objects appear in the object list"
      ]
    },
    {
      "id": 2,
      "title": "Initialize Domains and Grid",
      "objective": "Start with all positions possible, then apply hard filters",
      "procedure": [
        "Set state.domains[obj] = {1,2,3,4,5} for each object",
        "Initialize a 5x5 grid with true (candidate) for each (object, position)",
        "Apply global assumptions (e.g., not at ends) to shrink domains immediately"
      ],
      "outputs": [
        "Initialized domains and grid"
      ],
      "checks": [
        "All domains non-empty"
      ]
    },
    {
      "id": 3,
      "title": "Apply Strongest Constraints First (Anchors)",
      "objective": "Rapidly reduce search space using ends and immediates",
      "procedure": [
        "Place fixed positions (pos(A) = k)",
        "Restrict ends (at an end / not at an end)",
        "Apply immediate left/right constraints to forbid impossible end positions",
        "Record adjacency requirements and their immediate implications near ends"
      ],
      "outputs": [
        "Updated domains/grid",
        "Initial order/adjacency chains"
      ],
      "checks": [
        "Contradictions detected early (empty domains) trigger backtrack or ambiguity review"
      ]
    },
    {
      "id": 4,
      "title": "Propagate Constraints",
      "objective": "Iteratively eliminate impossible positions and extend chains",
      "procedure": [
        "Loop over propagation_rules in a fixed order until no changes:",
        "- Merge order relations into chains (A < B < C) and bound feasible blocks",
        "- Enforce adjacency/non-adjacency eliminations",
        "- Enforce between constraints; remove ends for betweenness",
        "- Apply mutual exclusion after any singleton assignment",
        "- After every change, run consistency check"
      ],
      "outputs": [
        "Shrunk domains and updated chains",
        "Derived placements when domains collapse to singletons"
      ],
      "checks": [
        "If any domain empty, mark contradiction"
      ]
    },
    {
      "id": 5,
      "title": "Branch on Most Constrained Variable (MRV)",
      "objective": "If unresolved, make the smallest, most informative guess",
      "procedure": [
        "Select object with smallest domain size > 1",
        "Push current state to decision_stack",
        "Try each candidate position in domain (ordered):",
        "- Tentatively assign pos(obj) = k",
        "- Propagate constraints (Step 4)",
        "- If contradiction, revert and try next k",
        "- If complete assignment found, proceed to verification"
      ],
      "outputs": [
        "A complete candidate ordering or exhaustion of candidates"
      ],
      "checks": [
        "Backtrack on first detected contradiction to minimize search"
      ]
    },
    {
      "id": 6,
      "title": "Verify Solution",
      "objective": "Ensure the ordering satisfies every constraint",
      "procedure": [
        "For each constraint in state.constraints, evaluate against the candidate order",
        "If any constraint fails, backtrack to Step 5",
        "If all pass, add to solutions; if the question seeks a single order, check for uniqueness"
      ],
      "outputs": [
        "state.solutions (one or more valid orders)"
      ],
      "checks": [
        "Report if multiple solutions exist and the question requires uniqueness"
      ]
    },
    {
      "id": 7,
      "title": "Answer the Question",
      "objective": "Return the requested output format",
      "procedure": [
        "If question = full_order and exactly one solution, return that order",
        "If multiple solutions, either list them or state the non-uniqueness per instructions",
        "If question = specific_relation (e.g., who is third? is X left of Y?), compute the answer over all solutions:",
        "- If invariant across all solutions, return the invariant answer",
        "- If varies, report ambiguity and the set of possibilities"
      ],
      "outputs": [
        "Final answer and, if relevant, the full ordering(s)"
      ],
      "checks": [
        "Double-check the final reported order(s) matches constraints"
      ]
    }
  ],
  "data_handling": {
    "domains_representation": "Map object -> set of feasible positions",
    "grid_representation": "Map object -> {pos: true/false} or 5x5 boolean table",
    "chains_tracking": {
      "order_chains": "List of lists representing A < B < C sequences",
      "adjacency": "List of unordered pairs or directed immediates for A = B ± 1"
    },
    "logging": {
      "entry_format": "reason, affected_objects, change, constraint_source",
      "example": "reason: 'immediate-left forbids end', affected: ['A','B'], change: 'remove A=5,B=1', source: 'A = B - 1'"
    }
  },
  "verification": {
    "checks": [
      "All objects assigned distinct positions in {1..5}",
      "Every constraint evaluates to true",
      "If more than one solution, confirm constraints do not imply uniqueness"
    ]
  },
  "examples_of_constraint_translation": [
    {
      "text": "C is immediately to the left of D",
      "formal": "pos(C) = pos(D) - 1",
      "immediate_implications": "C != 5, D != 1"
    },
    {
      "text": "A is between B and E",
      "formal": "min(pos(B), pos(E)) < pos(A) < max(pos(B), pos(E))",
      "immediate_implications": "A in {2,3,4}"
    },
    {
      "text": "B is not at an end and is next to E",
      "formal": ["pos(B) in {2,3,4}", "|pos(B) - pos(E)| = 1"]
    },
    {
      "text": "D is to the right of A and left of C",
      "formal": ["pos(A) < pos(D)", "pos(D) < pos(C)"],
      "merged_chain": "A < D < C"
    }
  ],
  "solution_output_format": {
    "full_order": {
      "format": ["pos 1", "pos 2", "pos 3", "pos 4", "pos 5"],
      "example": ["A", "B", "C", "D", "E"]
    },
    "relations": {
      "position_of_X": "k",
      "left_of": "true/false/depends",
      "neighbor_pairs": [["X","Y"], ["Y","Z"]]
    }
  }
}

