      }
    },
    "domain": "real|complex (default: real)",
    "output_form": "fraction|decimal|exact_radical|mixed_number (default: fraction for rationals, exact_radical for radicals if present)"
  },
  "policies": {
    "exact_preference": "Prefer exact fractions and exact radicals unless decimal output is explicitly requested.",
    "no_premature_rounding": true,
    "implicit_multiplication": "Treat adjacency (e.g., 2(3), (a)(b), (2/3)x) as multiplication.",
    "power_associativity": "right (a^b^c = a^(b^c))",
    "mult_div_associativity": "left",
    "add_sub_associativity": "left",
    "unary_minus": "Parse as multiplication by (-1) where helpful; -a^b means -(a^b) unless parentheses indicate otherwise."
  },
  "data_structures": {
    "tokens": "List of tokens (numbers, variables if any, operators + - * / ^, parentheses ( ) ).",
    "groups": "Innermost parenthetical ranges identified by indices.",
    "trace": "Ordered list of step objects recording sub-expressions and substitutions for transparency."
  },
